import React from "react";

const Values = {
    intro: {
        title: 'Att leva med våld',
        summary: 'Möt Gulderen. Gulderen har i 22 år levt i en nära relation som har präglats av våld. Du får följa hennes livsberättelse där hon pratar om våldet, vilka konsekvenser det har fått och hur hon har tagit sig vidare.',
        video: {
            title: 'Intro',
            link: 'https://www.youtube-nocookie.com/embed/2_cWs41AGtw',
        },
        subtitle: 'Vad är våld?',
        paragraphs: [
            'FN:s deklaration om avskaffande av våld mot kvinnor, som antogs år 1993 (FN, 1993). I den definieras mäns våld mot kvinnor som:',
            <em>”Varje könsrelaterad våldshandling som resulterar i, eller troligen kommer att leda till, fysisk, sexuell eller psykisk skada eller lidande för kvinnor, samt hot om sådana handlingar, tvång eller godtyckligt frihetsberövande, vare sig det sker i det offentliga eller privata livet.”</em>,
            'Våld är varje handling riktad mot en annan person, som genom att denna handling skadar, smärtar, skrämmer eller kränker, får denna person att göra något mot sin vilja eller avstå från att göra något som den vill.” (Sinisalo, E. Hällen, L. Våld i nära relation. 2018 s.35).',
        ],
    },
}
export default Values;
